prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?task
  (COALESCE(?taskName, STR(?task)) AS ?taskLabel)
  ?choreo
  ?start
  (COALESCE(?startName, STR(?start)) AS ?startLabel)
WHERE {
  ?model a bboExt:Model .
  ?model tai:normalizedId "3c1c7ac2bf4042fe9cd4ed34ce14a188" .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .
  OPTIONAL { ?start bbo:name ?startName . }

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?taskName . }

  FILTER NOT EXISTS {
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?idProp
  ?idValue
  ?model
  ?modelName
  (COUNT(DISTINCT ?choreo) AS ?choreoCount)
WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:normalizedId ?idValue . BIND("normalizedId" AS ?idProp) }
  OPTIONAL { ?model tai:originalId ?idValue2 . BIND("originalId" AS ?idProp2) }

  FILTER(
    (EXISTS { ?model tai:normalizedId "3c1c7ac2bf4042fe9cd4ed34ce14a188" } ) ||
    (EXISTS { ?model tai:originalId "3c1c7ac2bf4042fe9cd4ed34ce14a188" } )
  )

  OPTIONAL {
    ?model bbo:name ?modelName .
  }

  OPTIONAL {
    ?defs tai:belongsTo ?model .
    ?choreo a bboExt:Choreography ;
            tai:belongsTo ?defs .
  }
}
GROUP BY ?idProp ?idValue ?model ?modelName
ORDER BY ?modelName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?task
  (COALESCE(?taskName, STR(?task)) AS ?taskLabel)
  ?choreo
  (COALESCE(?startName, STR(?start)) AS ?startLabel)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "sid_bce75566_36a6_4093_94c7_b431843dafc9" .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .
  OPTIONAL { ?start bbo:name ?startName . }

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?taskName . }

  FILTER NOT EXISTS {
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?node
  (COALESCE(?nodeName, STR(?node)) AS ?nodeLabel)
  (GROUP_CONCAT(DISTINCT STR(?t); separator=", ") AS ?types)
  (COUNT(DISTINCT ?inEdge) AS ?incomingSeqFlows)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "sid_bce75566_36a6_4093_94c7_b431843dafc9" .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?node tai:belongsTo ?choreo .
  OPTIONAL { ?node bbo:name ?nodeName . }
  OPTIONAL { ?node a ?t . }
  OPTIONAL {
    ?inEdge a bbo:SequenceFlow ;
            bbo:has_targetRef ?node .
  }
}
GROUP BY ?node ?nodeName
HAVING (COUNT(DISTINCT ?inEdge) = 0)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?task
  (COALESCE(?taskName, STR(?task)) AS ?taskLabel)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "sid_bce75566_36a6_4093_94c7_b431843dafc9" .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?taskName . }

  FILTER NOT EXISTS {
    ?entry
      ((^bbo:has_sourceRef)/bbo:has_targetRef)+
      ?task .

    ?entry tai:belongsTo ?choreo .

    FILTER NOT EXISTS {
      ?inEdge a bbo:SequenceFlow ;
              bbo:has_targetRef ?entry .
    }
  }
}
LIMIT 25
